  static autoGenerate(schema1: BuiltSchema, schema2: BuiltSchema, wasm: WasmModule): ProtolensChainHandle {
    try {
      const rawHandle = wasm.exports.auto_generate_protolens(schema1._handle.id, schema2._handle.id);
